import React, { useState, useEffect } from 'react';
import { Users, Building2, TrendingUp, Activity, Calendar, DollarSign, UserCheck, Briefcase } from 'lucide-react';
import { format } from 'date-fns';

const StatCard = ({ title, value, icon: Icon, color, change }) => (
  <div className="card">
    <div className="flex items-center justify-between">
      <div>
        <p className="text-sm font-medium text-gray-600">{title}</p>
        <p className="text-2xl font-bold text-gray-900 mt-2">{value}</p>
        {change && (
          <p className={`text-sm mt-2 ${change >= 0 ? 'text-green-600' : 'text-red-600'}`}>
            {change >= 0 ? '+' : ''}{change}% from last month
          </p>
        )}
      </div>
      <div className={`p-3 rounded-lg ${color}`}>
        <Icon className="h-6 w-6 text-white" />
      </div>
    </div>
  </div>
);

const RecentActivity = ({ title, items, type }) => {
  const getTypeColor = (active) => active ? 'status-active' : 'status-inactive';

  return (
    <div className="card">
      <h3 className="text-lg font-semibold text-gray-900 mb-4">{title}</h3>
      <div className="space-y-3">
        {items?.slice(0, 5).map((item) => (
          <div key={item.id} className="flex items-center justify-between py-2">
            <div className="flex-1">
              <p className="text-sm font-medium text-gray-900">
                {type === 'student' ? item.fullName : item.companyName}
              </p>
              <p className="text-xs text-gray-500">
                {type === 'student' ? item.email : item.industry}
              </p>
            </div>
            <div className="text-right">
              <span className={`status-badge ${getTypeColor(item.active)}`}>
                {item.active ? 'Active' : 'Inactive'}
              </span>
              <p className="text-xs text-gray-500 mt-1">
                {format(new Date(item.registrationDate), 'MMM dd, yyyy')}
              </p>
            </div>
          </div>
        ))}
        {(!items || items.length === 0) && (
          <p className="text-gray-500 text-center py-4">No recent {type}s</p>
        )}
      </div>
    </div>
  );
};

const Dashboard = () => {
  const [dashboardData, setDashboardData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Mock data for demonstration - replace with actual API call
    const mockData = {
      totalStudents: 1247,
      activeStudents: 892,
      totalCompanies: 156,
      activeCompanies: 134,
      recentStudents: [
        { id: 1, fullName: 'Rahul Kumar', email: 'rahul.kumar@college.edu', active: true, registrationDate: '2024-03-15' },
        { id: 2, fullName: 'Priya Sharma', email: 'priya.sharma@college.edu', active: true, registrationDate: '2024-03-14' },
        { id: 3, fullName: 'Amit Patel', email: 'amit.patel@college.edu', active: false, registrationDate: '2024-03-13' },
        { id: 4, fullName: 'Neha Gupta', email: 'neha.gupta@college.edu', active: true, registrationDate: '2024-03-12' },
        { id: 5, fullName: 'Vikram Singh', email: 'vikram.singh@college.edu', active: true, registrationDate: '2024-03-11' }
      ],
      recentCompanies: [
        { id: 1, companyName: 'Tech Solutions Inc', industry: 'Software Development', active: true, registrationDate: '2024-03-15' },
        { id: 2, companyName: 'Global Systems', industry: 'IT Services', active: true, registrationDate: '2024-03-14' },
        { id: 3, companyName: 'Data Analytics Pro', industry: 'Data Science', active: false, registrationDate: '2024-03-13' },
        { id: 4, companyName: 'CloudTech Industries', industry: 'Cloud Computing', active: true, registrationDate: '2024-03-12' },
        { id: 5, companyName: 'CyberSec Solutions', industry: 'Cybersecurity', active: true, registrationDate: '2024-03-11' }
      ]
    };

    setTimeout(() => {
      setDashboardData(mockData);
      setLoading(false);
    }, 1000); // Simulate loading
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  const stats = [
    {
      title: 'Total Students',
      value: dashboardData?.totalStudents || 0,
      icon: Users,
      color: 'bg-blue-500',
      change: 12
    },
    {
      title: 'Active Students',
      value: dashboardData?.activeStudents || 0,
      icon: Activity,
      color: 'bg-green-500',
      change: 8
    },
    {
      title: 'Total Companies',
      value: dashboardData?.totalCompanies || 0,
      icon: Building2,
      color: 'bg-purple-500',
      change: 15
    },
    {
      title: 'Active Companies',
      value: dashboardData?.activeCompanies || 0,
      icon: TrendingUp,
      color: 'bg-orange-500',
      change: 10
    }
  ];

  return (
    <div>
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-600 mt-2">Welcome to the placement admin panel</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {stats.map((stat, index) => (
          <StatCard key={index} {...stat} />
        ))}
      </div>

      {/* Recent Activity */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <RecentActivity 
          title="Recent Students" 
          items={dashboardData?.recentStudents}
          type="student"
        />
        <RecentActivity 
          title="Recent Companies" 
          items={dashboardData?.recentCompanies}
          type="company"
        />
      </div>
    </div>
  );
};

export default Dashboard;
